SELECT COUNT(episode_id) AS episodes_appeared
FROM character_episodes
WHERE character_id = 0;

SELECT COUNT(*) AS total_posts
FROM forum_posts
WHERE user_id = 0;

SELECT actor_name
FROM actors
WHERE awards_won = (
  SELECT MAX(awards_won)
  FROM actors
);

SELECT actor_name
FROM actors
WHERE actor_id IN (SELECT actor_id FROM awards);

